public class RevenueUpdateJob implements Queueable {
    private List<Id> accountIds;
    public RevenueUpdateJob(List<Id> ids) {
        this.accountIds = ids;
    }
    public void execute(QueueableContext ctx) {
        List<Account> toUpdate = [
            SELECT Id, AnnualRevenue
            FROM Account
            WHERE Id IN :accountIds
        ];
        for (Account a : toUpdate) {
            a.AnnualRevenue = a.AnnualRevenue * 1.03;
        }
        update toUpdate;
    }
}
List<Id> sampleIds = new List<Id>{'001D000000IqhSL'};
System.enqueueJob(new RevenueUpdateJob(sampleIds));
